content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě, kě yǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de5 na2 tie3, ke3 yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "請給我一杯冰的紅茶，半糖，可以嗎？",
      "pinyin": "Qǐng gěi wǒ yī bēi bīng de hóng chá, bàn táng, kě yǐ ma?",
      "pinyin_numeric": "qing3 gei3 wo3 yi1 bei1 bing1 de5 hong2 cha2, ban4 tang2, ke3 yi3 ma0?",
      "translation_en": "Please give me an iced black tea, half sugar, okay?",
      "translation_ko": "얼음 홍차 한 잔, 반 당으로 주세요, 괜찮을까요?"
    },
    {
      "text": "我想要一杯熱的綠茶，不加糖，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi rè de lǜ chá, bù jiā táng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 re4 de5 lü4 cha2, bu4 jia1 tang2, ke3 yi3 ma0?",
      "translation_en": "I would like a hot green tea, no sugar, okay?",
      "translation_ko": "뜨거운 녹차 한 잔, 설탕 없이 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，我要一杯豆漿，少冰，可以嗎？",
      "pinyin": "Má fan nǐ, wǒ yào yī bēi dòu jiāng, shǎo bīng, kě yǐ ma?",
      "pinyin_numeric": "ma2 fan5 ni3, wo3 yao4 yi1 bei1 dou4 jiang1, shao3 bing1, ke3 yi3 ma0?",
      "translation_en": "Excuse me, I want a soy milk, less ice, okay?",
      "translation_ko": "실례합니다, 두유 한 잔, 얼음 적게 주세요, 괜찮을까요?"
    },
    {
      "text": "不好意思，我想要一杯中杯的拿鐵，加珍珠，可以嗎？",
      "pinyin": "Bù hǎo yì si, wǒ xiǎng yào yī bēi zhōng bēi de ná tiě, jiā zhēn zhū, kě yǐ ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, wo3 xiang3 yao4 yi1 bei1 zhong1 bei1 de5 na2 tie3, jia1 zhen1 zhu1, ke3 yi3 ma0?",
      "translation_en": "Excuse me, I would like a medium latte with pearls, okay?",
      "translation_ko": "죄송합니다, 중간 크기 라떼에 타피오카 펄 추가해서 원하는데 괜찮을까요?"
    },
    {
      "text": "店員，我要一杯大杯的紅茶，正常甜，外帶，可以嗎？",
      "pinyin": "Diàn yuán, wǒ yào yī bēi dà bēi de hóng chá, zhèng cháng tián, wài dài, kě yǐ ma?",
      "pinyin_numeric": "dian4 yuan2, wo3 yao4 yi1 bei1 da4 bei1 de5 hong2 cha2, zheng4 chang2 tian2, wai4 dai4, ke3 yi3 ma0?",
      "translation_en": "Shop assistant, I want a large black tea, normal sweetness, for takeout, okay?",
      "translation_ko": "점원님, 큰 홍차 한 잔, 보통 당도, 포장으로 주세요, 괜찮을까요?"
    },
    {
      "text": "客人，你要內用還是外帶？我要內用，可以嗎？",
      "pinyin": "Kè rén, nǐ yào nèi yòng hái shì wài dài? Wǒ yào nèi yòng, kě yǐ ma?",
      "pinyin_numeric": "ke4 ren2, ni3 yao4 nei4 yong4 hai2 shi4 wai4 dai4? wo3 yao4 nei4 yong4, ke3 yi3 ma0?",
      "translation_en": "Customer, do you want for here or to go? I want for here, okay?",
      "translation_ko": "손님, 매장에서 드실 건가요 포장하실 건가요? 매장에서 먹을게요, 괜찮을까요?"
    },
    {
      "text": "麻煩你，給我一個袋子，可以嗎？",
      "pinyin": "Má fan nǐ, gěi wǒ yī ge dài zi, kě yǐ ma?",
      "pinyin_numeric": "ma2 fan5 ni3, gei3 wo3 yi1 ge5 dai4 zi5, ke3 yi3 ma0?",
      "translation_en": "Excuse me, give me a bag, okay?",
      "translation_ko": "실례합니다, 봉투 하나 주세요, 괜찮을까요?"
    },
    {
      "text": "不好意思，可以幫我拿一根吸管嗎？",
      "pinyin": "Bù hǎo yì si, kě yǐ bāng wǒ ná yī gēn xī guǎn ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 bang1 wo3 na2 yi1 gen1 xi1 guan3 ma0?",
      "translation_en": "Excuse me, can you help me get a straw?",
      "translation_ko": "죄송합니다, 빨대 하나 가져다 주시겠어요?"
    },
    {
      "text": "店員，這個價錢是多少？可以再說一次嗎？",
      "pinyin": "Diàn yuán, zhè ge jià qián shì duō shǎo? Kě yǐ zài shuō yī cì ma?",
      "pinyin_numeric": "dian4 yuan2, zhe4 ge5 jia4 qian2 shi4 duo1 shao3? ke3 yi3 zai4 shuo1 yi1 ci4 ma0?",
      "translation_en": "Shop assistant, how much is this price? Can you say it again?",
      "translation_ko": "점원님, 이 가격이 얼마인가요? 한 번 더 말씀해 주시겠어요?"
    }
  ]
}
